commands.cmd:
set --
[ -n '' ] && set -- "$@" --context ''
if [ -n '' ]; then
  kubectl get namespace '' "$@" >/dev/null || { echo "namespace not found or not readable" >&2; exit 1; }
  set -- "$@" -n ''
else
  set -- "$@" -A
fi
pods=$(kubectl get pods "$@" -o json) || { echo "kubectl get pods failed" >&2; exit 1; }
printf '%s' "$pods" | jq -c '{
  results: [
    .items[]
    | select(.status.phase == "Failed" and .status.reason == "Evicted")
    | {
        name: .metadata.name,
        namespace: .metadata.namespace,
        message: (.status.message // "")
      }
  ]
}' || { echo "jq failed" >&2; exit 1; }
